// ── Length validator (max 5000 chars) ──────────────────────────────
const text  = ($input.first().json && $input.first().json.text) || '';
const mlCfg = $input.all().find(i => i.json && i.json.mlServiceUrl);
const mlErr = $input.all().find(i => i.json && i.json.error);
const MAX   = 5000;

if (mlErr) {
  return [{json: {error: `ML config fetch failed: ${mlErr.json.error}`, statusCode: 503}}];
}
if (!mlCfg || !mlCfg.json.mlServiceUrl) {
  return [{json: {error: 'ML service URL not found in Firestore config ml_config/sentiment-ml-v1. Run deploy.sh to initialise.', statusCode: 503}}];
}

const textItem = $input.all().find(i => i.json && i.json.text !== undefined);
if (!textItem) { return [{json: {error: 'No input payload', statusCode: 400}}]; }

// Merge ML config into the validated-text item
textItem.json.mlServiceUrl = mlCfg.json.mlServiceUrl;
textItem.json.mlApiKey     = mlCfg.json.mlApiKey || '';
return [textItem];

// ── Standardise and return ML results ─
const ml  = $input.item.json;
const raw = $input.all().find(i => i.json && i.json.text);
const meta = $input.item.metadata || {};

let sentiment  = (ml.sentiment  || 'unknown').toLowerCase();
let confidence = parseFloat(ml.confidence ?? 0);

if (sentiment !== 'positive' && sentiment !== 'negative') sentiment = 'neutral';
confidence = Math.max(0, Math.min(1, confidence));

const reqAt   = new Date().toISOString();
const tracer  = meta.runId || null;
const cfwd    = meta.headers && meta.headers['x-forwarded-for']
             || meta.headers && meta.headers['X-Forwarded-For'];

return [{
  json: {
    sentiment:      sentiment,
    confidence:     confidence,
    positive_score: sentiment === 'positive' ? confidence : 1 - confidence,
    negative_score: sentiment === 'negative' ? confidence : 1 - confidence,
    neutral_score:  sentiment === 'neutral'  ? confidence : (1 - confidence) * 0.5,
    processed_at:   ml.processed_at || new Date().toISOString(),
    requested_at:   reqAt,
    request_ip:     cfwd || null,
    tracer_id:      tracer,
    model:          ml.model || 'unknown',
  }
}];

